wire_code.init:
encKey, err := hex.DecodeString(cfg.MessagingEncryptionKey)
if err != nil { return nil, fmt.Errorf("MESSAGING_ENCRYPTION_KEY must be 64-char hex: %w", err) }
if len(encKey) != 32 { return nil, fmt.Errorf("MESSAGING_ENCRYPTION_KEY must be 32 bytes (64 hex chars)") }
rateLimit := 10
if cfg.MessagingDefaultRateLimit != "" { rateLimit, _ = strconv.Atoi(cfg.MessagingDefaultRateLimit) }
workerCount := 5
if cfg.MessagingWorkerCount != "" { workerCount, _ = strconv.Atoi(cfg.MessagingWorkerCount) }
emailProvider := cfg.MessagingEmailProvider
if emailProvider == "" { emailProvider = "sendgrid" }
var emailAPIKey string
switch emailProvider {
case "sendgrid": emailAPIKey = cfg.SendGridAPIKey
case "mailgun": emailAPIKey = cfg.MailgunAPIKey
case "postmark": emailAPIKey = cfg.PostmarkServerToken
}
smsProvider := cfg.MessagingSMSProvider
if smsProvider == "" { smsProvider = "msg91" }
var smsAPIKey string
switch smsProvider {
case "msg91": smsAPIKey = cfg.MSG91AuthKey
case "twilio": smsAPIKey = cfg.TwilioAccountSID
}
emailFrom := cfg.MessagingEmailFromAddr
if emailFrom == "" { emailFrom = "noreply@example.com" }
emailName := cfg.MessagingEmailFromName
if emailName == "" { emailName = "Spur" }
smsSender := cfg.MessagingSMSSenderID
if smsSender == "" { smsSender = "SPUR" }
messagingCfg := messaging.Config{EncryptionKey: encKey, WebhookBaseURL: cfg.MessagingWebhookBaseURL, DefaultRateLimit: rateLimit, WorkerCount: workerCount, EmailProvider: emailProvider, EmailAPIKey: emailAPIKey, EmailFromAddress: emailFrom, EmailFromName: emailName, EmailTrackOpens: cfg.MessagingEmailTrackOpens != "false", EmailTrackClicks: cfg.MessagingEmailTrackClicks != "false", SMSProvider: smsProvider, SMSAPIKey: smsAPIKey, SMSSenderID: smsSender, WhatsAppWebhookVerifyToken: cfg.WhatsAppWebhookVerifyToken, WhatsAppMetaAppID: cfg.WhatsAppMetaAppID}
messagingLog := infra.Log.Logger()
messagingModule, err := messaging.New(ctx, messaging.Options{DB: infra.DB, Log: &messagingLog, Cfg: messagingCfg, Redis: infra.Redis})
if err != nil { return nil, fmt.Errorf("messaging: %w", err) }
messagingPermissions := make([]identitydomain.ManifestPermission, 0, len(msgpermissions.Catalog))
for _, permission := range msgpermissions.Catalog { messagingPermissions = append(messagingPermissions, identitydomain.ManifestPermission{Slug: permission.Key, Description: permission.Description}) }
messagingRoleTemplates := make([]identitydomain.ManifestRoleTemplate, 0, len(msgpermissions.RoleTemplates))
for _, template := range msgpermissions.RoleTemplates { messagingRoleTemplates = append(messagingRoleTemplates, identitydomain.ManifestRoleTemplate{Code: template.Code, Name: template.Name, Description: template.Description, Permissions: append([]string(nil), template.Permissions...)}) }
if err := identityModule.Services.ModuleService.RegisterManifest(ctx, identitydomain.Manifest{Name: "Messaging", Code: msgpermissions.ModuleCode, Description: "Messaging channels, templates, contacts, campaigns, delivery reports, and analytics.", Permissions: messagingPermissions, RoleTemplates: messagingRoleTemplates}); err != nil { return nil, fmt.Errorf("register messaging manifest: %w", err) }
